import { createFileRoute } from '@tanstack/react-router';
import React, { Suspense } from 'react';
import { PageTabs } from '@/components/PageTabs';
import { AttendeeTabs } from '@/constants/Routes';
import { PageLoader } from '@/components/ui/PageLoader';

const Attendee = React.lazy(() => import('@/pages/attendee/Attendee').then(m => ({ default: m.Attendee })));

function Page() {
  return (
    <PageTabs tabs={AttendeeTabs}>
      <Suspense fallback={<PageLoader />}>
        <Attendee />
      </Suspense>
    </PageTabs>
  );
}

export const Route = createFileRoute('/_auth/attendee/')({
  component: Page,
});

