import { createFileRoute, useParams } from '@tanstack/react-router';
import { BusinessUpdate } from '@/pages/business/BusinessUpdate';
import { PageTabs } from '@/components/PageTabs';
import { BusinessTabs } from '@/constants/Routes';

export const Route = createFileRoute('/_auth/business/edit/$id')({
  component: function Page() {
    const { id } = useParams({ from: '/_auth/business/edit/$id' });
    return (
      <>
        <PageTabs tabs={BusinessTabs} />
        <BusinessUpdate businessId={id} />
      </>
    );
  },
});
