import React from "react";
import BottomNavigation from '@mui/material/BottomNavigation';
import BottomNavigationAction from '@mui/material/BottomNavigationAction';
import { useNavigate, useLocation } from '@tanstack/react-router';
import { IPages } from "./Sidebar/child/SidebarNav";
import MenuIcon from '@mui/icons-material/Menu';
import { GetUserRoles } from "../../utils/token";
import { hasRequiredRole } from '@/utils/roles';
import { semanticColors, elevation, zIndex } from '@/constants/ThemeConstants';

export const boottomNavStyles: React.CSSProperties = {
  position: 'fixed',
  zIndex: zIndex.bottomNav,
  bottom: 0,
  left: 0,
  right: 0,
  width: '100%',
  borderTop: `1px solid ${semanticColors.border.subtle}`,
  boxShadow: elevation[3],
  backgroundColor: semanticColors.surface.card,
  paddingBottom: 'env(safe-area-inset-bottom)',
};

export interface MobileFooterNavProps {
  pages: IPages[];
  onSidebarOpen(): void;
}

export const MobileFooterNav = (props: MobileFooterNavProps) => {
  const [value, setValue] = React.useState('recents');
  const navigate = useNavigate();
  const { pathname: currentPathName } = useLocation();
  const userRoles = GetUserRoles();

  // Filter pages based on user roles
  const filteredPages = props.pages.filter(page => hasRequiredRole(page.role, userRoles));

  // Set value on route change
  React.useEffect(() => {
    setValue(currentPathName);
  }, [currentPathName]);

  return (
    <BottomNavigation
      component="nav"
      aria-label="Primary mobile navigation"
      showLabels
      value={value}
      style={boottomNavStyles}
      sx={{
        '& .MuiBottomNavigationAction-root': {
          minWidth: 'auto',
          padding: '4px 0',
          borderRadius: 1,
          transition: 'background-color 0.2s',
          '&.Mui-selected': {
            padding: '4px 0',
            backgroundColor: 'action.selected',
            '& .MuiBottomNavigationAction-label': {
              fontSize: '0.65rem',
            },
          },
          '& .MuiBottomNavigationAction-label': {
            fontSize: '0.65rem',
          },
          '& .MuiSvgIcon-root': {
            fontSize: '1.25rem',
          },
        },
      }}
    >
      {filteredPages.map((page: IPages) => (
        <BottomNavigationAction
          key={page.href}
          label={page.title}
          value={page.href}
          icon={page.icon}
          onClick={() => {
            setValue(page.href);
            navigate({ to: page.href });
          }}
        />
      ))}
      <BottomNavigationAction
          label={"Menu"}
          icon={<MenuIcon />}
          onClick={() => {
            props.onSidebarOpen();
          }}
        />
    </BottomNavigation>
  );
};

