import React from 'react';
import ReactDOM from 'react-dom/client';
import { RouterProvider, createRouter } from '@tanstack/react-router';
import { HelmetProvider } from 'react-helmet-async';
import { routeTree } from './routeTree.gen';
import { AuthContextProvider } from '@/contexts/AuthProvider';
import { UpdateKeyContext, useKeyContext } from '@/contexts/UpdateKeyContext';
import { IsTokenValid, GetUserRoles } from '@/utils/token';
import './globals.css';

const router = createRouter({
  routeTree,
  context: {
    auth: {
      isAuthenticated: false,
      roles: [],
    },
  },
});

declare module '@tanstack/react-router' {
  interface Register {
    router: typeof router;
  }
}

function InnerApp() {
  const { updateKey } = useKeyContext();
  const [authState, setAuthState] = React.useState({
    isAuthenticated: IsTokenValid(),
    roles: GetUserRoles() ?? [],
  });

  // Expose a way for Login/Logout to trigger auth re-evaluation
  React.useEffect(() => {
    const handler = () => {
      const newAuth = {
        isAuthenticated: IsTokenValid(),
        roles: GetUserRoles() ?? [],
      };
      setAuthState(newAuth);
      // Force router to re-evaluate beforeLoad with new context
      router.invalidate();
    };
    window.addEventListener('auth-changed', handler);
    return () => window.removeEventListener('auth-changed', handler);
  }, []);

  // Dismiss splash screen after app has rendered
  React.useEffect(() => {
    const splash = document.getElementById('splash');
    if (splash) {
      splash.classList.add('fade-out');
      setTimeout(() => splash.remove(), 500);
    }
  }, []);

  return (
    <AuthContextProvider>
      <UpdateKeyContext.Provider value={updateKey}>
        <RouterProvider router={router} context={{ auth: authState }} />
      </UpdateKeyContext.Provider>
    </AuthContextProvider>
  );
}

ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <HelmetProvider>
      <InnerApp />
    </HelmetProvider>
  </React.StrictMode>
);
