import React, { useState, useEffect } from 'react';
import { Box, useMediaQuery, Grid } from '@mui/material';
import { useTheme, createTheme, ThemeProvider } from '@mui/material/styles';
import { Sidebar } from './child/Sidebar/Sidebar';
import { Footer } from './child/Footer';
import { Topbar } from './child/Topbar';
import { LayoutConfig } from './LayoutConfig';
import { useAuth } from '@/contexts/AuthProvider';
import { IsProfileComplete } from '@/utils/token';
import { RightColumn } from './child/RightColumn';
import { MobileFooterNav } from './child/MobileFooterNav';
import { spacing, semanticColors, radius, motion, easing, zIndex as appZIndex } from '@/constants/ThemeConstants';
import { useEnforceRouteRoles } from '@/hooks/useEnforceRouteRoles';

const buildMuiTheme = () => {
  const palette = semanticColors;
  return createTheme({
    palette: {
      mode: 'light',
      primary: {
        main: palette.accent.primary,
        dark: palette.accent.primaryHover,
        contrastText: palette.text.onPrimary,
      },
      error: { main: palette.state.error },
      success: { main: palette.state.success },
      warning: { main: palette.state.warning },
      info: { main: palette.state.info },
      background: {
        default: palette.surface.app,
        paper: palette.surface.card,
      },
      text: {
        primary: palette.text.primary,
        secondary: palette.text.secondary,
        disabled: palette.text.muted,
      },
      divider: palette.border.subtle,
    },
    shape: {
      borderRadius: radius.md,
    },
    transitions: {
      duration: {
        shortest: motion.fast,
        shorter: motion.fast,
        short: motion.base,
        standard: motion.base,
        complex: motion.slow,
        enteringScreen: motion.base,
        leavingScreen: motion.fast,
      },
      easing: {
        easeInOut: easing.standard,
        easeOut: easing.emphasized,
        easeIn: easing.exit,
        sharp: easing.exit,
      },
    },
    zIndex: {
      appBar: appZIndex.appBar,
      drawer: appZIndex.drawerTemporary,
      modal: appZIndex.modal,
      snackbar: appZIndex.snackbar,
      tooltip: appZIndex.tooltip,
    },
    typography: {
      fontFamily: 'Roboto, Helvetica, Arial, sans-serif',
      h1: {
        fontSize: '2.25rem',
        fontWeight: 300,
        lineHeight: 1.2,
        color: palette.text.primary,
        '@media (max-width:600px)': { fontSize: '1.875rem' },
      },
      h2: {
        fontSize: '2rem',
        fontWeight: 400,
        lineHeight: 1.2,
        color: palette.text.primary,
        '@media (max-width:600px)': { fontSize: '1.625rem' },
      },
      h3: {
        fontSize: '1.625rem',
        fontWeight: 400,
        lineHeight: 1.2,
        color: palette.text.primary,
        '@media (max-width:600px)': { fontSize: '1.375rem' },
      },
      h4: {
        fontSize: '1.375rem',
        fontWeight: 500,
        lineHeight: 1.2,
        color: palette.text.primary,
        '@media (max-width:600px)': { fontSize: '1.1875rem' },
      },
      h5: {
        fontSize: '1.1875rem',
        fontWeight: 600,
        lineHeight: 1.25,
        color: palette.text.primary,
        '@media (max-width:600px)': { fontSize: '1.0625rem' },
      },
      h6: {
        fontSize: '1.0625rem',
        fontWeight: 600,
        lineHeight: 1.25,
        color: palette.text.primary,
        '@media (max-width:600px)': { fontSize: '1rem' },
      },
      subtitle1: {
        color: palette.text.primary,
      },
      subtitle2: {
        color: palette.text.primary,
      },
      body1: {
        fontSize: '0.9375rem',
        lineHeight: 1.5,
        color: palette.text.primary,
      },
      body2: {
        fontSize: '0.9375rem',
        lineHeight: 1.5,
        color: palette.text.primary,
      },
      caption: {
        color: palette.text.secondary,
      },
    },
    components: {
      MuiTextField: {
        defaultProps: {
          fullWidth: true,
        },
      },
      MuiButton: {
        styleOverrides: {
          root: {
            textTransform: 'none',
          },
        },
      },
      MuiToggleButton: {
        styleOverrides: {
          root: {
            textTransform: 'none',
          },
        },
      },
      MuiTab: {
        styleOverrides: {
          root: {
            textTransform: 'none',
          },
        },
      },

    },
  });
};


const rootStyle: React.CSSProperties = {
  padding: 0,
  fontFamily: 'Roboto, Helvetica, Arial, sans-serif',
  height: '100%',
};

const layoutDesktopStyle: React.CSSProperties = {
  paddingTop: spacing.topbarHeight,
  height: '100%',
  paddingLeft: spacing.sidebarWidth
};

const layoutDesktopUnAuthStyle: React.CSSProperties = {
  paddingTop: spacing.topbarHeight,
  height: '100%'
};

const layoutMobileStyle: React.CSSProperties = {
  paddingTop: spacing.topbarHeight,
  height: '100%',
  paddingLeft: 0
};

const mainStyle: React.CSSProperties = {
  minHeight: `calc(100dvh - ${spacing.topbarHeight}px)`,
  margin: '0px 5% 0px 5%',
  display: 'flex',
  flexDirection: 'column'
};

const contentStyle: React.CSSProperties = {
  flex: 1
};

const footerContainerStyle: React.CSSProperties = {
  textAlign: 'center'
};

export interface LayoutProps {
  children: React.ReactNode;
}

const LayoutInner: React.FC<LayoutProps> = (props) => {
  const muiTheme = React.useMemo(() => buildMuiTheme(), []);
  const theme = useTheme();
  const [openSidebar, setOpenSidebar] = useState(false);

  const isMobile = useMediaQuery(theme.breakpoints.down('sm'), {
    defaultMatches: true
  });

  const isLargeScreen = useMediaQuery(theme.breakpoints.up('lg'), {
    defaultMatches: true
  });

  useEffect(() => {
    if (isMobile) {
      setOpenSidebar(false);
    }
    else {
      setOpenSidebar(true);
    }
  }, [isMobile]);

  const handleSidebarOpen = () => {
    setOpenSidebar(true);
  };

  const handleSidebarClose = () => {
    setOpenSidebar(false);
  };

  const shouldOpenSidebar = isMobile ? openSidebar : true;
  const isAuthenticated = useAuth();
  useEnforceRouteRoles();

  // Global modal scroll-lock: mirror MUI's body lock onto <html> so background
  // never scrolls when ANY Dialog / Drawer / Modal / Popover / Menu is open
  // (especially important for iOS Safari where body overflow:hidden alone
  // doesn't always block touch scroll).
  useEffect(() => {
    const html = document.documentElement;
    const body = document.body;
    const sync = () => {
      const locked = body.style.overflow === 'hidden';
      html.classList.toggle('modal-open', locked);
    };
    sync();
    const observer = new MutationObserver(sync);
    observer.observe(body, { attributes: true, attributeFilter: ['style'] });
    return () => {
      observer.disconnect();
      html.classList.remove('modal-open');
    };
  }, []);

  return (
    <ThemeProvider theme={muiTheme}>
    <div style={{ ...rootStyle, backgroundColor: semanticColors.surface.app }}>
      {/* Skip link — first focusable element for keyboard users (WCAG 2.4.1). */}
      <a
        href="#main-content"
        style={{
          position: 'absolute',
          left: -9999,
          top: 8,
          zIndex: appZIndex.modal + 1,
          padding: '8px 12px',
          background: semanticColors.surface.card,
          color: semanticColors.text.primary,
          border: `2px solid ${semanticColors.accent.primary}`,
          borderRadius: radius.sm,
          textDecoration: 'none',
          fontWeight: 600,
        }}
        onFocus={(e) => { e.currentTarget.style.left = '8px'; }}
        onBlur={(e) => { e.currentTarget.style.left = '-9999px'; }}
      >
        Skip to main content
      </a>
      <div style={isAuthenticated ? (isMobile ? layoutMobileStyle : layoutDesktopStyle) : (isMobile ? layoutMobileStyle : layoutDesktopUnAuthStyle)}>
        <Topbar
          onSidebarOpen={handleSidebarOpen}
          logoUrl={LayoutConfig.TopbarProps.logoUrl}
          siteTitle={LayoutConfig.TopbarProps.siteTitle}
        />
        {isAuthenticated && (
          <Sidebar
            onClose={handleSidebarClose}
            open={shouldOpenSidebar}
            variant={isMobile ? 'temporary' : 'persistent'}
          />
        )}
        <main id="main-content" tabIndex={-1} aria-label="Main content" style={mainStyle}>
          <section style={contentStyle}>
            {!isMobile && isAuthenticated ? (
              <Grid container spacing={8}>
                {
                  isLargeScreen ? (
                    <>
                      <Grid size={{ xs: 8 }}>
                        {props.children}
                      </Grid>
                      <Grid size={{ xs: 4 }}>
                        <Box
                          component="aside"
                          aria-label="Digital identity card"
                          sx={{
                            position: 'sticky',
                            top: `${spacing.topbarHeight + 24}px`,
                            minWidth: 320,
                            maxWidth: 380,
                            mx: 'auto',
                          }}
                        >
                          <RightColumn />
                        </Box>
                      </Grid>
                    </>
                  ) : (
                    <Grid size={{ xs: 12 }}>
                      {props.children}
                    </Grid>
                  )
                }
              </Grid>
            ) : (
              props.children
            )}
          </section>
          <div style={footerContainerStyle}>
            {isMobile && isAuthenticated && IsProfileComplete() && (
              <MobileFooterNav 
                pages={LayoutConfig.BottomNavPages} 
                onSidebarOpen={handleSidebarOpen} 
              />
            )}
            <Footer {...LayoutConfig.FooterProps} />
          </div>
        </main>
      </div>
    </div>
    </ThemeProvider>
  );
};

export const Layout: React.FC<LayoutProps> = (props) => (
  <LayoutInner>{props.children}</LayoutInner>
);

