import { createFileRoute } from '@tanstack/react-router';
import React, { Suspense } from 'react';
import { PageTabs } from '@/components/PageTabs';
import { ProfileTabs } from '@/constants/Routes';
import { PageLoader } from '@/components/ui/PageLoader';

const ProfilePhotoUpdate = React.lazy(() => import('@/pages/profile/ProfilePhotoUpdate').then(m => ({ default: m.ProfilePhotoUpdate })));

function Page() {
  return (
    <>
      <PageTabs tabs={ProfileTabs} />
      <Suspense fallback={<PageLoader />}>
        <ProfilePhotoUpdate />
      </Suspense>
    </>
  );
}

export const Route = createFileRoute('/_auth/profile/photo')({
  component: Page,
});

