import { Component, ReactNode } from 'react';
import { Box, Typography, Button, Stack } from '@mui/material';
import { logger } from '@/utils/logger';

interface Props {
  children: ReactNode;
  /** Optional scope label used in logs (e.g. route name). */
  scope?: string;
  /** Optional fallback render override. */
  fallback?: (error: Error, reset: () => void) => ReactNode;
}
interface State { hasError: boolean; error?: Error; }

export class ErrorBoundary extends Component<Props, State> {
  state: State = { hasError: false };

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: { componentStack?: string | null }) {
    logger.error(this.props.scope ?? 'ErrorBoundary', 'Render error', { error, componentStack: info.componentStack });
  }

  reset = () => this.setState({ hasError: false, error: undefined });

  render() {
    if (this.state.hasError && this.state.error) {
      if (this.props.fallback) return this.props.fallback(this.state.error, this.reset);
      return (
        <Box sx={{ p: 4, textAlign: 'center' }} role="alert">
          <Typography variant="h5" gutterBottom>Something went wrong</Typography>
          <Typography color="text.secondary" sx={{ mb: 2 }}>{this.state.error.message}</Typography>
          <Stack direction="row" spacing={1} sx={{ justifyContent: 'center' }}>
            <Button variant="outlined" onClick={this.reset}>Try Again</Button>
            <Button variant="contained" onClick={() => window.location.reload()}>Reload Page</Button>
          </Stack>
        </Box>
      );
    }
    return this.props.children;
  }
}
