import React from "react";
import { AppBar, Toolbar, IconButton, Stack, useMediaQuery, useTheme } from "@mui/material";
import MenuIcon from "@mui/icons-material/Menu";
import { Link } from '@tanstack/react-router';
import { LoginLogoutButton } from "./LoginLogoutButton";
import NotificationsIcon from '@mui/icons-material/Notifications';
import { Pathname } from "../../constants/Routes";

import { colors, spacing, elevation, zIndex } from '@/constants/ThemeConstants';

const rootStyle: React.CSSProperties = {
  boxShadow: elevation[1],
  height: spacing.topbarHeight,
  zIndex: zIndex.appBar,
  paddingTop: 'env(safe-area-inset-top)',
};

const toolbarStyle: React.CSSProperties = {
  height: spacing.topbarHeight,
  minHeight: spacing.topbarHeight,
};

const flexGrowStyle: React.CSSProperties = {
  flexGrow: 1,
};

// Topbar lives inside MUI AppBar (primary brand color). Foreground colors
// resolve to white via theme.palette.primary.contrastText.
const siteTitleStyle: React.CSSProperties = {
  color: colors.textOnPrimary,
  margin: "0 0 0 0px",
};

const notificationStyle: React.CSSProperties = {
  color: colors.textOnPrimary,
}

const logoStyle: React.CSSProperties = {
  height: 40,
  width: 32,
  paddingTop: 5,
  marginRight: 4,
};

const linkStyle: React.CSSProperties = {
  textDecoration: "none",
};

export interface TopbarProps {
  onSidebarOpen(): void;
  logoUrl: string;
  siteTitle: string;
}

export const Topbar: React.FC<TopbarProps> = (props) => {
  const showNotificationButton = false;
  const showLoginLogoutButton = true;
  const handleNotificationClick = () => {
  }

  const theme = useTheme();
  const isDesktop = useMediaQuery(theme.breakpoints.up("lg"), {
    defaultMatches: true,
  });

  return (
    <>
      <AppBar style={rootStyle}>
        <Toolbar style={toolbarStyle}>
          <Stack direction="row" sx={{ alignItems: 'center' }} spacing={{ xs: 0.5, sm: 1 }}>
            {
              props.logoUrl === "" ? null : (
                <Link to={Pathname.Root as string} style={linkStyle}>
                  <img src={props.logoUrl} alt={props.siteTitle} style={logoStyle} />
                </Link>
              )
            }
            <Link to={Pathname.Root as string} style={linkStyle} aria-label={`${props.siteTitle} — home`}>
              <span style={{ ...siteTitleStyle, fontSize: '1.0625rem', fontWeight: 500, display: 'inline-block' }}>
                {props.siteTitle}
              </span>
            </Link>
          </Stack>

          <div style={flexGrowStyle} />
          <Stack direction="row" sx={{ alignItems: 'center' }} spacing={1}>
            {
              showNotificationButton && (
                <IconButton aria-label="notification" style={notificationStyle} onClick={handleNotificationClick}>
                  <NotificationsIcon />
                </IconButton>
              )
            }
            {
              showLoginLogoutButton && (
                <LoginLogoutButton />
              )
            }
            {isDesktop ? null : (
              <IconButton
                onClick={props.onSidebarOpen}
                aria-label="Menu"
                sx={{
                  color: colors.textOnPrimary,
                  bgcolor: 'primary.dark',
                  '&:hover': { bgcolor: 'primary.dark', filter: 'brightness(0.9)' },
                }}
              >
                <MenuIcon />
              </IconButton>
            )}
          </Stack>
        </Toolbar>
      </AppBar>
    </>
  );
};

