import { createFileRoute } from '@tanstack/react-router';
import React, { Suspense } from 'react';
import { PageTabs } from '@/components/PageTabs';
import { IdentityTabs } from '@/constants/Routes';
import { PageLoader } from '@/components/ui/PageLoader';

const IdentityView = React.lazy(() => import('@/pages/identity/IdentityView').then(m => ({ default: m.IdentityView })));

function Page() {
  return (
    <>
      <PageTabs tabs={IdentityTabs} />
      <Suspense fallback={<PageLoader />}>
        <IdentityView />
      </Suspense>
    </>
  );
}

export const Route = createFileRoute('/_auth/identity/')({
  component: Page,
});

