import { createRootRouteWithContext, Outlet, ScrollRestoration, useLocation } from '@tanstack/react-router';
import { Layout } from '@/layout/Layout';
import { NavigationProgress } from '@/components/NavigationProgress';
import { GlobalLoadingBackdrop } from '@/components/GlobalLoadingBackdrop';
import { Helmet } from 'react-helmet-async';
import { RoutesMetadata } from '@/constants/Routes';
import { LayoutConfig } from '@/layout/LayoutConfig';
import { EnvConfig } from '@/constants/EnvConfig';
import { ErrorBoundary } from '@/components/ErrorBoundary';
import { useEffect } from 'react';

export interface MyRouterContext {
  auth: {
    isAuthenticated: boolean;
    roles: string[];
  };
}

export const Route = createRootRouteWithContext<MyRouterContext>()({
  component: RootComponent,
});

function RootComponent() {
  const { pathname } = useLocation();
  const matchedRouteData = RoutesMetadata.find((i: { route: string }) => i.route === pathname);
  const defaultData = {
    title: LayoutConfig.SiteName,
    description: `The official website of ${LayoutConfig.SiteName}.`,
  };

  const pageTitle = matchedRouteData?.title || defaultData.title;
  const pageDescription = matchedRouteData?.description || defaultData.description;

  useEffect(() => {
    document.title = pageTitle;
  }, [pageTitle]);

  return (
    <>
      <Helmet>
        <meta name="description" content={pageDescription} />
        <meta property="og:type" content="website" />
        <meta property="og:title" content={pageTitle} />
        <meta property="og:description" content={pageDescription} />
        <meta property="og:image" content={EnvConfig.SiteLogo} />
      </Helmet>
      <NavigationProgress />
      <GlobalLoadingBackdrop />
      <ScrollRestoration />
      <ErrorBoundary>
        <Layout>
          <Outlet />
        </Layout>
      </ErrorBoundary>
    </>
  );
}
