import React from "react";
import FavoriteIcon from "@mui/icons-material/Favorite";
import { Link } from '@tanstack/react-router';
import { colors } from '@/constants/ThemeConstants';
import { EnvConfig } from '@/constants/EnvConfig';

// Note: heart icon keeps brand red across both themes — intentional.
// Version label uses CSS opacity so it dims correctly in both modes.

const rootStyle: React.CSSProperties = {
  padding: "10px 5px 70px 5px",
};

const desktopRootStyle: React.CSSProperties = {
  padding: "10px 5px 10px 5px",
};

const iconStyle: React.CSSProperties = {
  fontSize: 12,
  color: colors.heartRed,
};

export interface FooterProps {
  aboutUrl: string;
  copyrightOwner: string;
  licenseUrl: string;
  privacyPolicyUrl: string;
  indiaFlagSvgUrl: string;
}

export const Footer = (props: FooterProps) => {
  const [isMobile, setIsMobile] = React.useState(false);

  React.useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
    };

    handleResize(); // Set initial value
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  const appliedRootStyle = isMobile ? rootStyle : desktopRootStyle;
  
  return (
    <footer role="contentinfo" style={appliedRootStyle}>
      <span style={{ fontSize: '0.7rem' }}>
        <Link to={props.licenseUrl as string}>© {props.copyrightOwner} {new Date().getFullYear()}</Link>
        {" | "}
        <Link to={props.aboutUrl as string}>About</Link>
        {" | "}
        <Link to={props.privacyPolicyUrl as string}>Privacy</Link>
        {" | "}
        <span style={{ whiteSpace: 'nowrap' }}>
          {"Made with "}
          <FavoriteIcon style={iconStyle} />
          {" in Bharat "}
          <img src={props.indiaFlagSvgUrl} alt="India" height="11" width="20" />
        </span>
        {" | "}
        <span style={{ fontSize: '0.6rem', opacity: 0.6 }}>{EnvConfig.SiteVersion}</span>
      </span>
    </footer>
  );
};

