import React from "react";
import { List, ListItemButton, ListItemIcon, Divider, ListItemText, ListItem, useMediaQuery, useTheme } from "@mui/material";
import { useLocation, useNavigate } from '@tanstack/react-router';
import { SidebarNavFooter } from "./SidebarNavFooter";
import { LayoutConfig } from "../../../LayoutConfig";
import { GetUserRoles, IsProfileComplete } from "@/utils/token";
import { Roles } from "@/types/api.types";
import { fontWeights } from '@/constants/ThemeConstants';
import WhatsAppIcon from '@mui/icons-material/WhatsApp';
import { ProfileServices } from '@/api';
import { getWhatsAppGroup, openWhatsAppGroup, WhatsAppGroupConfig } from '@/constants/StaticData';

const listItemButtonActiveClassName = "Mui-selected";

const listItemStyle: React.CSSProperties = {
  padding: 0,
};

const linkStyle: React.CSSProperties = {
  textDecoration: "none",
  width: "100%",
};

// Color omitted so MUI ListItemButton inherits theme.palette.text.* tokens
// (looks correct in both light and dark modes).
const linkTextStyle: React.CSSProperties = {
  fontWeight: fontWeights.medium,
  letterSpacing: "normal",
  lineHeight: "22px",
};

const uniqueKey = (pre: number): string => {
  return `${pre}`;
};

export interface ISocialLinks {
  Github: string;
  LinkedIn: string;
  Twitter: string;
  YouTube: string;
  Telegram: string;
}

export interface IPages {
  title: string;
  href: string;
  icon: React.ReactNode;
  role?: Roles | Roles[];
}

// Reusable NavItem component to reduce duplication
const NavItem: React.FC<{ page: IPages; currentPath: string; useAnchor?: boolean; onNavigate: (href: string) => void }> = ({ 
  page, 
  currentPath, 
  useAnchor = false,
  onNavigate
}) => (
  <ListItem component="div" style={listItemStyle}>
    <ListItemButton 
      component={useAnchor ? "a" : "div"} 
      href={useAnchor ? page.href : undefined} 
      onClick={useAnchor ? undefined : () => onNavigate(page.href)}
      aria-label={page.title} 
      className={currentPath === page.href ? listItemButtonActiveClassName : ""} 
      style={linkStyle}
    >
      <ListItemIcon>{page.icon}</ListItemIcon>
      <ListItemText primary={<span style={linkTextStyle}>{page.title}</span>} />
    </ListItemButton>
  </ListItem>
);

export const SidebarNav: React.FunctionComponent = () => {
  const { pathname } = useLocation();
  const navigate = useNavigate();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'), { noSsr: true });
  const [pathName, setPathName] = React.useState("");
  const [waGroup, setWaGroup] = React.useState<WhatsAppGroupConfig | undefined>();

  React.useEffect(() => {
    setPathName(pathname);
  }, [pathname]);

  React.useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const res = await ProfileServices.GetProfile();
        if (cancelled) return;
        const profile = res?.data?.result;
        if (!profile) return;
        setWaGroup(getWhatsAppGroup(profile.firstJnvId, profile.location));
      } catch { /* ignore */ }
    })();
    return () => { cancelled = true; };
  }, []);
  
  const userRoles = GetUserRoles();
  const profileComplete = IsProfileComplete();
  
  // Helper function to check if user has required role(s)
  const hasRequiredRole = (pageRole?: Roles | Roles[]): boolean => {
    if (!pageRole) return true; // No role requirement means everyone can access
    
    // SuperAdmin has access to everything
    if (userRoles.includes(Roles.SuperAdmin)) return true;
    
    // Handle both single role and array of roles
    const requiredRoles = Array.isArray(pageRole) ? pageRole : [pageRole];
    
    // Check if user has any of the required roles
    return requiredRoles.some(role => userRoles.includes(role));
  };
  
  const currentPath = pathName.length > 1 && pathName.endsWith("/") 
    ? pathName.slice(0, -1) 
    : pathName;

  // Filter pages based on roles
  const filteredSidebarPages = LayoutConfig.SidebarNavPages.filter(page => hasRequiredRole(page.role));
  const filteredPrivatePages = LayoutConfig.SidebarNavPrivatePages.filter(page => hasRequiredRole(page.role));

  return (
    <>
      <List component="nav" role="navigation" aria-label="Main navigation">
        {!profileComplete ? (
          // Incomplete profile: show limited pages
          LayoutConfig.IncompleteProfilePages.map((page, index) => (
            <NavItem key={uniqueKey(index)} page={page} currentPath={currentPath} useAnchor onNavigate={(href) => navigate({ to: href })} />
          ))
        ) : (
          // Regular sidebar pages with role filtering
          filteredSidebarPages.map((page, index) => (
            <NavItem key={uniqueKey(index)} page={page} currentPath={currentPath} onNavigate={(href) => navigate({ to: href })} />
          ))
        )}
        
        {filteredPrivatePages.length > 0 && (
          <>
            <Divider />
            {filteredPrivatePages.map((page, index) => (
              <NavItem key={`private_${uniqueKey(index)}`} page={page} currentPath={currentPath} onNavigate={(href) => navigate({ to: href })} />
            ))}
          </>
        )}
        {isMobile && waGroup && (
          <>
            <Divider />
            <ListItem component="div" style={listItemStyle}>
              <ListItemButton
                onClick={() => openWhatsAppGroup(waGroup)}
                style={linkStyle}
              >
                <ListItemIcon><WhatsAppIcon sx={{ color: '#25D366' }} /></ListItemIcon>
                <ListItemText
                  primary={<span style={linkTextStyle}>Join WhatsApp Group</span>}
                  secondary={<span style={{ fontSize: '0.8rem', opacity: 0.7 }}>{waGroup.label}</span>}
                />
              </ListItemButton>
            </ListItem>
          </>
        )}
      </List>

      <SidebarNavFooter {...LayoutConfig.SidebarNavFooterProps} />
    </>
  );
};

