import { PropsWithChildren, useContext, useEffect, useMemo, useState } from "react"
import { AuthContext, AuthData } from "./AuthContext"
import { IsEmptyObj } from "../utils/common"
import { IsTokenValid } from "../utils/token"

export const AuthContextProvider = ({ children }: PropsWithChildren) => {
  const [authData, setAuthData] = useState({} as AuthData)
  const [isAuthenticated, setIsAuthenticated] = useState(false)

  useEffect(() => {
    setIsAuthenticated(IsTokenValid())
  }, [])

  useEffect(() => {
    if (!IsEmptyObj(authData)) { setIsAuthenticated(true) }
  }, [authData])

  useEffect(() => {
    if (!isAuthenticated) { setAuthData({} as AuthData) }
  }, [isAuthenticated])

  const contextValue = useMemo(() => ({
    isAuthenticated,
    setIsAuthenticated,
    authData,
    setAuthData
  }), [isAuthenticated, setIsAuthenticated, authData, setAuthData])

  return (
    <AuthContext.Provider value={contextValue}>
      {children}
    </AuthContext.Provider>
  )
}

// Full context — for components that need auth details
export const useAuthContext = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuthContext must be used within AuthContextProvider');
  return context;
};

// Boolean shortcut — for guard checks
export const useIsAuthenticated = (): boolean => useAuthContext().isAuthenticated;

// Backward compatible alias
export const useAuth = useIsAuthenticated;
