import React from "react";
import { Divider, Drawer, useMediaQuery, useTheme } from "@mui/material";
import { Profile } from "./child/Profile";
import { SidebarNav } from "./child/SidebarNav";
import { LayoutConfig } from "../../LayoutConfig";
import { spacing, elevation, zIndex } from '@/constants/ThemeConstants';
import { useBodyScrollLock } from '@/hooks/useBodyScrollLock';

const drawerPaperMobileStyle: React.CSSProperties = {
  width: spacing.sidebarWidth,
  marginTop: 0,
  height: "100%",
  border: "none",
  boxShadow: elevation[3],
  zIndex: zIndex.drawerTemporary,
};

const drawerPaperDesktopStyle: React.CSSProperties = {
  width: spacing.sidebarWidth,
  marginTop: `${spacing.topbarHeight}px`,
  height: `calc(100% - ${spacing.topbarHeight}px)`,
  border: "none",
  boxShadow: elevation[1],
  zIndex: zIndex.drawerPersistent,
};

const rootStyle: React.CSSProperties = {
  display: "flex",
  flexDirection: "column",
  height: "100%",
  padding: 15,
};

export interface SidebarProps {
  open: boolean;
  variant: "permanent" | "persistent" | "temporary" | undefined;
  onClose(): void;
}

export const Sidebar: React.FC<SidebarProps> = (props) => {
  const { open, variant, onClose } = props;
  const theme = useTheme();
  const isDesktop = useMediaQuery(theme.breakpoints.up("lg"), {
    defaultMatches: true,
  });

  // Apply body scroll lock when mobile drawer is open
  useBodyScrollLock(!isDesktop && open);

  return (
    <>
      {props !== undefined && (
        <>
          <Drawer
            anchor="left"
            slotProps={{ paper: { style: isDesktop ? drawerPaperDesktopStyle : drawerPaperMobileStyle } }}
            onClose={onClose}
            open={open}
            variant={variant}
            component={"div"}
          >
            <div style={rootStyle} onClick={onClose}>
              <Profile {...LayoutConfig.ProfileProps} />
              <Divider />
              <SidebarNav />
            </div>
          </Drawer>
        </>
      )}
    </>
  );
};

