import { createFileRoute, useParams } from '@tanstack/react-router';
import EventViewPage from '@/pages/events/EventViewPage';
import { PageTabs } from '@/components/PageTabs';
import { EventTabs } from '@/constants/Routes';

export const Route = createFileRoute('/_auth/events/view/$id')({
  component: function Page() {
    const { id } = useParams({ from: '/_auth/events/view/$id' });
    return (
      <>
        <PageTabs tabs={EventTabs} />
        <EventViewPage eventId={id} />
      </>
    );
  },
});
