import { createFileRoute, redirect } from '@tanstack/react-router';
import { Schools } from '@/constants/StaticData';
import { GetAccessTokenData } from '@/utils/token';

export const Route = createFileRoute('/_auth/search/batchmates')({
  beforeLoad: () => {
    const tokenData = GetAccessTokenData() as any;
    if (tokenData?.firstJnvId && tokenData?.entryYear) {
      const school = Schools.find(s => s.UniqueId === tokenData.firstJnvId);
      throw redirect({
        to: '/',
        search: {
          k: 'jnvBatch',
          j: school ? `JNV ${school.SchoolName} ${school.StatePrefix}` : '',
          b: String(tokenData.entryYear),
        },
      });
    }
    throw redirect({ to: '/' });
  },
});

