import { Button, Dialog, DialogActions, DialogContent, DialogContentText, DialogTitle, IconButton, Menu, MenuItem, ListItemIcon, ListItemText } from "@mui/material";
import React, { useContext, useState } from "react";
import PersonIcon from "@mui/icons-material/Person";
import RefreshIcon from "@mui/icons-material/Refresh";
import LogoutIcon from "@mui/icons-material/Logout";
import LoginIcon from "@mui/icons-material/Login";
import { useNavigate } from '@tanstack/react-router';
import { AuthContext } from "@/contexts/AuthContext";
import { AuthServices } from "@/api";
import { SetAccessTokenData } from "@/utils/token";
import { AuthTokenResult } from "@/types/auth.types";

export const LoginLogoutButton: React.FunctionComponent = () => {
  const { isAuthenticated, setAuthData } = useContext(AuthContext);
  const navigate = useNavigate();
  const [refreshing, setRefreshing] = useState(false);
  const [refreshResult, setRefreshResult] = useState<{ open: boolean; success: boolean; message: string }>({
    open: false,
    success: false,
    message: '',
  });

  const onLoginClick = () => {
    navigate({ to: '/login' });
  };

  const onLogoutClick = () => {
    navigate({ to: '/logout' });
  };

  const onRefreshClick = async () => {
    if (refreshing) return;
    setRefreshing(true);
    try {
      const response = await AuthServices.RefreshToken();
      const envelope = response.data as { status: number; result?: AuthTokenResult; error?: string };
      if (envelope?.status >= 200 && envelope.status < 300 && envelope.result?.accessToken) {
        SetAccessTokenData(envelope.result);
        setAuthData({ name: envelope.result.name, email: envelope.result.resource });
        window.dispatchEvent(new Event('auth-changed'));
        const roles = envelope.result.roles?.length ? envelope.result.roles.join(', ') : 'User';
        setRefreshResult({
          open: true,
          success: true,
          message: `Session refreshed. Active roles: ${roles}.`,
        });
      } else {
        setRefreshResult({
          open: true,
          success: false,
          message: envelope?.error || 'Failed to refresh session. Please try again.',
        });
      }
    } catch (err) {
      setRefreshResult({
        open: true,
        success: false,
        message: (err as Error)?.message || 'Failed to refresh session. Please try again.',
      });
    } finally {
      setRefreshing(false);
    }
  };

  const closeDialog = () => setRefreshResult((prev) => ({ ...prev, open: false }));

  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);

  return (
    <>
      {isAuthenticated ? (
        <>
          <IconButton
            aria-label="account"
            onClick={(e) => setAnchorEl(e.currentTarget)}
            sx={{
              color: 'common.white',
              bgcolor: 'primary.dark',
              '&:hover': { bgcolor: 'primary.dark', filter: 'brightness(0.9)' },
            }}
          >
            <PersonIcon />
          </IconButton>
          <Menu
            anchorEl={anchorEl}
            open={Boolean(anchorEl)}
            onClose={() => setAnchorEl(null)}
            transformOrigin={{ horizontal: 'right', vertical: 'top' }}
            anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
          >
            <MenuItem onClick={() => { setAnchorEl(null); onRefreshClick(); }} disabled={refreshing}>
              <ListItemIcon><RefreshIcon fontSize="small" /></ListItemIcon>
              <ListItemText>{refreshing ? 'Refreshing...' : 'Refresh Login'}</ListItemText>
            </MenuItem>
            <MenuItem onClick={() => { setAnchorEl(null); onLogoutClick(); }}>
              <ListItemIcon><LogoutIcon fontSize="small" /></ListItemIcon>
              <ListItemText>Logout</ListItemText>
            </MenuItem>
          </Menu>
        </>
      ) : (
        <IconButton aria-label="login" sx={{ color: 'warning.light' }} onClick={onLoginClick}>
          <LoginIcon />
        </IconButton>
      )}
      <Dialog open={refreshResult.open} onClose={closeDialog} maxWidth="xs" fullWidth>
        <DialogTitle>{refreshResult.success ? 'Login refreshed' : 'Refresh failed'}</DialogTitle>
        <DialogContent>
          <DialogContentText>{refreshResult.message}</DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={closeDialog} autoFocus>OK</Button>
        </DialogActions>
      </Dialog>
    </>
  );
};

