import { useEffect } from 'react';
import { useLocation, useNavigate } from '@tanstack/react-router';
import { LayoutConfig } from '@/layout/LayoutConfig';
import { GetUserRoles, IsTokenValid } from '@/utils/token';
import { hasRequiredRole } from '@/utils/roles';
import { Pathname } from '@/constants/Routes';

// Watches `auth-changed` events and the current path; if the user no longer satisfies
// the role required for the current page, redirect them home.
export const useEnforceRouteRoles = () => {
    const location = useLocation();
    const navigate = useNavigate();

    useEffect(() => {
        const check = () => {
            if (!IsTokenValid()) return; // unauthenticated flows handled elsewhere
            const path = location.pathname;
            const all = [...LayoutConfig.SidebarNavPages, ...LayoutConfig.SidebarNavPrivatePages];
            // Match the most specific (longest) configured prefix.
            const match = all
                .filter(p => p.href && (path === p.href || path.startsWith(p.href + '/')))
                .sort((a, b) => (b.href?.length ?? 0) - (a.href?.length ?? 0))[0];
            if (!match || !match.role) return;
            const userRoles = GetUserRoles();
            if (!hasRequiredRole(match.role, userRoles)) {
                navigate({ to: Pathname.Root, search: {} as any } as any);
            }
        };
        check();
        window.addEventListener('auth-changed', check);
        return () => window.removeEventListener('auth-changed', check);
    }, [location.pathname, navigate]);
};
